// ─── Demo Data ────────────────────────────────────────────────────────────────
// Realistic mock data for the free interactive school demo.
// All data is interconnected: students belong to classes, classes belong to
// teachers, and aggregates roll up correctly.
// ──────────────────────────────────────────────────────────────────────────────

// ─── Types ────────────────────────────────────────────────────────────────────

export interface DemoTeacher {
  id: string
  name: string
  email: string
  role: "head_of_department" | "teacher" | "nqt" | "head_of_year"
  classes: string[]
  lastActive: string
  activeThisWeek: boolean
  department: string
  studentCount: number
  classCount: number
  avgProgress: number
  yearsExperience?: number
  cpdNotes?: string[]
}

export interface DemoModuleProgress {
  name: string
  progress: number
  score: number
  status?: string
}

export interface DemoMockExam {
  name: string
  score: number
  grade: string
  date: string
}

export interface DemoEssay {
  title: string
  score: number
  feedback: string
  date: string
  teacherReviewed?: boolean
}

export interface DemoQuizAttempt {
  name: string
  score: number
  maxScore: number
  date: string
}

export interface DemoActivity {
  action: string
  detail?: string
  date: string
  type?: string
}

export interface DemoStudent {
  id: string
  name: string
  email: string
  yearGroup: string
  className: string
  teacher: string
  overallProgress: number
  averageScore: number
  assignmentsCompleted: number
  assignmentsTotal: number
  lastActive: string
  status: "on-track" | "needs-support" | "at-risk" | "excelling"
  strengths: (string | { name: string; score: number })[]
  weaknesses: (string | { name: string; score: number })[]
  recentScores: number[]
  mockExamResults: { exam: string; score: number; grade: string; date: string }[]
  essaySubmissions: { title: string; score: number; feedback: string; date: string }[]
  moduleProgress: { module: string; progress: number; score: number; status: string }[]
  quizAttempts: { quiz: string; score: number; maxScore: number; date: string }[]
  activityLog: { action: string; date: string }[]
  recommendations: string[]
  atRisk: boolean
  riskReason: string
  classId: string
  teacherName: string
  modulesCompleted: number
  modules: DemoModuleProgress[]
  mockExams: DemoMockExam[]
  essays: DemoEssay[]
  activityTimeline: DemoActivity[]
}

export interface DemoClass {
  id: string
  name: string
  yearGroup: string
  examBoard: string
  teacher: string
  teacherId: string
  studentCount: number
  averageScore: number
  completionRate: number
  studentIds: string[]
  avgScore: number
  avgProgress: number
  assignmentsSet: number
  assignmentsCompleted: number
  atRiskCount?: number
  students?: Array<{
    id: string
    name: string
    overallScore: number
    overallProgress: number
    atRisk: boolean
    ragStatus: "green" | "amber" | "red"
    trend: "up" | "down" | "stable"
    lastActive: string
    assignmentsCompleted: number
    assignmentsTotal: number
    riskReason?: string
  }>
}

export interface DemoYearGroupStats {
  yearGroup: string
  year: number
  label: string
  studentCount: number
  classCount: number
  averageScore: number
  avgProgress: number
  completionRate: number
  atRiskCount: number
  excellingCount: number
  topModule: string
  weakestModule: string
}

export interface DemoAtRiskStudent {
  studentId: string
  name: string
  yearGroup: string
  className: string
  averageScore: number
  trend: "declining" | "stagnant" | "slightly-improving"
  reasons: string[]
  recommendedActions: string[]
  lastTeacherNote: string
  daysSinceActive: number
}

export interface DemoWeeklyActivity {
  week: string
  lessonsAccessed: number
  quizzesCompleted: number
  essaysSubmitted: number
  mockExamsTaken: number
  averageSessionMinutes: number
  activeStudents: number
}

export interface DemoResourceUsage {
  resourceId: string
  title: string
  type: "lesson" | "mock-exam" | "quiz" | "revision-guide" | "essay-prompt"
  accessCount: number
  averageScore: number | null
  yearGroup: string
  examBoard: string
}

export interface DemoAssignmentOverview {
  classId: string
  className: string
  teacher: string
  totalAssignments: number
  completed: number
  inProgress: number
  notStarted: number
  overdue: number
  averageScore: number
}

